const respuesta = $('🧠 FastAPI — Cerebro IA').first().json.respuesta || $input.first().json.respuesta || 'Hola! En qué puedo ayudarte?';
const telefono = $('Agregar Fecha').first().json.telefono;
const remoteJid = $('Agregar Fecha').first().json.remoteJid;

function escapeJson(str) {
  if (!str) return '';
  return str
    .replace(/\\/g, '\\\\')
    .replace(/"/g, '\\"')
    .replace(/\n/g, '\\n')
    .replace(/\r/g, '\\r')
    .replace(/\t/g, '\\t');
}

const bloques = respuesta.split('\n\n').filter(b => b.trim() !== '');

let parte_1 = '';
let parte_2 = '';
let parte_3 = '';

if (bloques.length === 1) {
  parte_1 = bloques[0].trim();
} else if (bloques.length === 2) {
  parte_1 = bloques[0].trim();
  parte_2 = bloques[1].trim();
} else if (bloques.length >= 3) {
  parte_1 = bloques[0].trim();
  parte_2 = bloques.slice(1, -1).join('\n\n').trim();
  parte_3 = bloques[bloques.length - 1].trim();
}

return {
  json: {
    telefono,
    remoteJid,
    parte_1,
    parte_2,
    parte_3,
    body_1: JSON.stringify({ number: telefono, text: parte_1 }),
    body_2: JSON.stringify({ number: telefono, text: parte_2 }),
    body_3: JSON.stringify({ number: telefono, text: parte_3 }),
    body_presence: JSON.stringify({ number: remoteJid, delay: 2000, presence: 'composing' })
  }
};

